async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const hero = await browser.extractComponent<{ recipeName: string; saveButtonSelector: string }>({
        typeName: 'RecipeHeroSection',
        schema: '{ recipeName: string; summary: string; addAllIngredientsSelector: string; saveButtonSelector: string; ingredients: { name: string; price: string; }[]; }'
    }, params.recipeName);
    if (!hero || !hero.saveButtonSelector) {
        throw new Error('Could not find recipe save button for: ' + params.recipeName);
    }
    await browser.click(hero.saveButtonSelector);
    await browser.awaitPageInteraction();
    return { success: true, message: 'Saved recipe: ' + hero.recipeName };
}
